SELECT id, email, phone, nickname, avatar_url, role, status, email_verified, phone_verified, last_login_at, created_at, updated_at FROM users WHERE role = #{role}
AND status = #{status}
AND status != 'DELETED'
AND (email LIKE CONCAT('%', #{keyword}, '%') OR nickname LIKE CONCAT('%', #{keyword}, '%'))
AND email LIKE CONCAT('%', #{email}, '%')
AND nickname LIKE CONCAT('%', #{nickname}, '%')
ORDER BY created_at DESC LIMIT #{offset}, #{size}

SELECT COUNT(*) FROM users WHERE role = #{role}
AND status = #{status}
AND status != 'DELETED'
AND (email LIKE CONCAT('%', #{keyword}, '%') OR nickname LIKE CONCAT('%', #{keyword}, '%'))
AND email LIKE CONCAT('%', #{email}, '%')
AND nickname LIKE CONCAT('%', #{nickname}, '%')

SELECT EXISTS(
    SELECT 1
    FROM waitlist_order
    WHERE user_id = #{userId}
      AND status IN ('PENDING_PAYMENT','WAITING')
)

SELECT EXISTS(
    SELECT 1
    FROM refund_record rr
    JOIN ticket_order o ON rr.order_id = o.id
    WHERE o.user_id = #{userId}
      AND rr.status NOT IN ('SUCCESS','FAILED','CANCELLED')
) OR EXISTS(
    SELECT 1
    FROM change_record cr
    JOIN ticket_order o ON cr.order_id = o.id
    WHERE o.user_id = #{userId}
      AND cr.status NOT IN ('SUCCESS','FAILED','CANCELLED')
)
